class Solution {
public:
    int longestPalindrome(string s, string t) {
        int n = s.size(), m = t.size();
        int best = 0;
        // helper to expand around center in combined string
        auto expand = [&](int l, int r) -> int {
            while (l >= 0 && r < n + m && s[l] == t[r - n]) {
                --l;
                ++r;
            }
            return r - l - 1;
        };
        // odd length centers
        for (int i = 0; i < n; ++i)
            best = max(best, expand(i, n + i));
        // even length centers
        for (int i = 0; i < n; ++i)
            best = max(best, expand(i, n + i + 1));
        // centers in t
        for (int j = 0; j < m; ++j) {
            best = max(best, expand(n - 1 - j, n + j));
            best = max(best, expand(n - 1 - j, n + j + 1));
        }
        // single char palindromes
        return max(best, 1);
    }
};
```
efficiency: HIGH
time complexity: O((n+m)^2)
space complexity: O(1)
energy implications: LOW
explanation: Treat the concatenation as a virtual string s + reverse(t) and expand around every possible center in O(1) space. The longest palindrome in this virtual string corresponds to the longest palindrome formed by concatenating substrings from s and t.

